# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self, db_path):
        self.db_path = db_path

    def check_permission(self, username, file_id):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        cursor.execute('SELECT access_level FROM permissions WHERE username=? AND file_id=?', (username, file_id))
        result = cursor.fetchone()
        conn.close()
        return result is not None and result[0] >= 1  # Assuming access_level >= 1 is required

    def read_file(self, username, file_id, file_path):
        if self.check_permission(username, file_id):
            with open(file_path, 'r') as file:
                return file.read()
        else:
            raise PermissionError("Permission denied: You do not have access to this file.")

